    "inlineSchema": "// This is your Prisma schema file,\n// learn more about it in the docs: https://pris.ly/d/prisma-schema\n\n// Get a free hosted Postgres database in seconds: `npx create-db`\n\ngenerator client {\n  provider     = \"prisma-client\"\n  output       = \"../src/generated/prisma\"\n  moduleFormat = \"cjs\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\nenum Currency {\n  RSD\n  EUR\n  USD\n}\n\nmodel User {\n  id           String        @id @default(uuid())\n  email        String        @unique\n  password     String\n  name         String\n  // Serbian business details\n  companyName  String?       @map(\"company_name\")\n  pib          String?       @unique // Poreski identifikacioni broj (Tax ID)\n  mbr          String?       @unique // Matični broj registracije\n  activityCode String?       @map(\"activity_code\") // Šifra delatnosti\n  address      String?\n  city         String?\n  postalCode   String?       @map(\"postal_code\")\n  municipality String? // Opština — affects tax coefficient\n  phone        String?\n  bankAccounts BankAccount[]\n  createdAt    DateTime      @default(now()) @map(\"created_at\")\n  updatedAt    DateTime      @updatedAt @map(\"updated_at\")\n  clients      Client[]\n  invoices     Invoice[]\n\n  @@map(\"users\")\n}\n\nmodel BankAccount {\n  id            String    @id @default(uuid())\n  userId        String    @map(\"user_id\")\n  bankName      String    @map(\"bank_name\")\n  accountNumber String    @map(\"account_number\") // Format: XXX-XXXXXXXXXX-XX\n  swiftCode     String?   @map(\"swift_code\")\n  iban          String?\n  currency      Currency  @default(RSD)\n  isDefault     Boolean   @default(false) @map(\"is_default\")\n  user          User      @relation(fields: [userId], references: [id], onDelete: Cascade)\n  createdAt     DateTime  @default(now()) @map(\"created_at\")\n  updatedAt     DateTime  @updatedAt @map(\"updated_at\")\n  invoices      Invoice[]\n\n  @@map(\"bank_accounts\")\n}\n\nenum ClientType {\n  DOMESTIC // Serbian client — taxId = PIB\n  INTERNATIONAL // Foreign client — taxId = VAT/EIN/etc\n}\n\nmodel Client {\n  id                 String     @id @default(uuid())\n  userId             String     @map(\"user_id\")\n  type               ClientType @default(DOMESTIC)\n  name               String\n  email              String?\n  phone              String?\n  address            String\n  city               String\n  postalCode         String?    @map(\"postal_code\")\n  country            String     @default(\"RS\") // ISO 3166-1 alpha-2\n  taxId              String     @map(\"tax_id\") // PIB for Serbian, VAT/EIN for foreign\n  registrationNumber String     @map(\"registration_number\") // MBR for Serbian\n  user               User       @relation(fields: [userId], references: [id], onDelete: Cascade)\n  createdAt          DateTime   @default(now()) @map(\"created_at\")\n  updatedAt          DateTime   @updatedAt @map(\"updated_at\")\n  invoices           Invoice[]\n\n  @@map(\"clients\")\n}\n\nenum InvoiceStatus {\n  DRAFT\n  SENT\n  PAID\n  CANCELLED\n}\n\nmodel Invoice {\n  id             String        @id @default(uuid())\n  userId         String        @map(\"user_id\")\n  clientId       String        @map(\"client_id\")\n  invoiceNumber  Int           @map(\"invoice_number\") // Sequential per user per year\n  year           Int // Year for numbering (e.g. 2026)\n  status         InvoiceStatus @default(DRAFT)\n  issueDate      DateTime      @map(\"issue_date\")\n  dueDate        DateTime      @map(\"due_date\")\n  placeOfIssue   String        @default(\"Beograd\") @map(\"place_of_issue\")\n  domesticSupply Boolean       @default(true) @map(\"domestic_supply\")\n  // true = mesto prometa u Srbiji → counts toward 8M\n  // false = mesto prometa van Srbije → does NOT count toward 8M\n  currency       Currency      @default(RSD)\n  exchangeRate   Decimal?      @map(\"exchange_rate\") // NBS rate if non-RSD\n  totalAmount    Decimal       @map(\"total_amount\") // In invoice currency\n  totalRsd       Decimal       @map(\"total_rsd\") // Always in RSD (for KPO)\n  note           String?\n  bankAccountId  String        @map(\"bank_account_id\")\n  user           User          @relation(fields: [userId], references: [id], onDelete: Cascade)\n  client         Client        @relation(fields: [clientId], references: [id])\n  bankAccount    BankAccount   @relation(fields: [bankAccountId], references: [id])\n  items          InvoiceItem[]\n  createdAt      DateTime      @default(now()) @map(\"created_at\")\n  updatedAt      DateTime      @updatedAt @map(\"updated_at\")\n\n  @@unique([userId, invoiceNumber, year]) // 1/2026 unique per user\n  @@map(\"invoices\")\n}\n\nmodel InvoiceItem {\n  id          String  @id @default(uuid())\n  invoiceId   String  @map(\"invoice_id\")\n  description String\n  quantity    Decimal\n  unitPrice   Decimal @map(\"unit_price\")\n  total       Decimal // quantity * unitPrice\n  invoice     Invoice @relation(fields: [invoiceId], references: [id], onDelete: Cascade)\n\n  @@map(\"invoice_items\")\n}\n",
